import{_ as a,o as r,c as i,ae as l}from"./chunks/framework.Czhw_PXq.js";const p=JSON.parse('{"title":"Diagram Platform Phase 2 对齐需求","description":"","frontmatter":{"date":"2026-04-14T00:00:00.000Z","topic":"diagram-platform-phase-2"},"headers":[],"relativePath":"brainstorms/2026-04-14-diagram-platform-phase-2-requirements.zh-CN.md","filePath":"brainstorms/2026-04-14-diagram-platform-phase-2-requirements.zh-CN.md"}'),t={name:"brainstorms/2026-04-14-diagram-platform-phase-2-requirements.zh-CN.md"};function o(d,e,n,s,c,m){return r(),i("div",null,[...e[0]||(e[0]=[l('<h1 id="diagram-platform-phase-2-对齐需求" tabindex="-1">Diagram Platform Phase 2 对齐需求 <a class="header-anchor" href="#diagram-platform-phase-2-对齐需求" aria-label="Permalink to &quot;Diagram Platform Phase 2 对齐需求&quot;">​</a></h1><h2 id="问题框架" tabindex="-1">问题框架 <a class="header-anchor" href="#问题框架" aria-label="Permalink to &quot;问题框架&quot;">​</a></h2><p>Notemd 的图表平台路线图已经不再是纸面设想。仓库当前已经落地了相当完整的 spec-first 流水线、多目标渲染器、预览与导出辅助能力，以及 locale/theme 对齐逻辑。现在的问题已经变了：实现现实已经跑在路线图前面，但原计划中部分架构承诺，在代码里仍然只实现了一半。</p><p>这种漂移会带来两个明确风险：</p><ul><li>后续工作可能会重复建设已经落地的能力</li><li>后续版本可能会对 runtime isolation、命令收口或 renderer 稳定性作出超过现状的承诺</li></ul><p>因此，下一阶段应该把重点放在产品化与边界加固，而不是继续增加 renderer 数量。</p><p>最近的稳定化工作已经把剩余 Mermaid legacy 表面往这个方向推进了一部分：render-host bundle 审计已经进入发布门禁，命令编排在 <code>src/main.ts</code> 中已经部分统一，共享 note-directive parsing / note attachment / edge-label surgery helper 也开始从 <code>src/mermaidProcessor.ts</code> 下沉到 <code>src/diagram/adapters/mermaid/legacyFixerUtils.ts</code>。当前未解决的问题已经不是“要不要开始拆分”，而是“在不破坏 legacy 修复覆盖面的前提下，剩余 sunset boundary 要推进到多激进”。</p><h2 id="需求" tabindex="-1">需求 <a class="header-anchor" href="#需求" aria-label="Permalink to &quot;需求&quot;">​</a></h2><p><strong>事实源对齐</strong></p><ul><li>R1. 仓库中必须存在一份可长期维护的文档，明确说明哪些 diagram-platform 能力已经发货、哪些仍处于实验阶段、哪些只完成了一部分、哪些被明确延后。</li><li>R2. <code>docs/superpowers/plans/2026-04-14-diagram-rendering-platform-roadmap.zh-CN.md</code> 必须逐段更新，使每个任务都反映当前实现状态、证据和剩余缺口。</li><li>R3. 面向用户和维护者的文档不得宣称当前代码尚未真正交付的 renderer isolation、打包保证或命令统一程度。</li></ul><p><strong>产品化方向</strong></p><ul><li>R4. spec-first 流水线在 best-fit routing 通过明确验收门槛之前，必须继续保留兼容当前 Mermaid 行为的路径。</li><li>R5. 下一批实现必须优先把已经落地但仍停留在 developer-only 或 experimental 表面的图表能力推进到稳定用户路径，再考虑新增 renderer 家族。</li><li>R6. Mermaid、JSON Canvas、Vega-Lite 与 HTML fallback 输出必须继续维护一份清晰的预览/导出契约，明确说明每个目标支持哪些 inline preview、SVG export、PNG export 与 raw-source save。</li><li>R7. 图表预览与导出行为必须在当前已发货 locale 目录内，与插件 UI locale 以及解析后的 Obsidian theme 保持一致。</li></ul><p><strong>架构控制</strong></p><ul><li>R8. 后续 renderer 工作必须复用 <code>DiagramSpec</code>、<code>RendererService</code> 与 target-aware save/export 流程，不能再把新的图表逻辑直接塞回 <code>src/main.ts</code>。</li><li>R9. build/runtime isolation 必须被视为独立加固里程碑；在打包与执行边界真正实现并验证前，不得把更重的 preview runtime 描述为“已隔离”。</li><li>R10. PlantUML、Graphviz、Draw.io 等高级引擎仍然保持延后，直到当前平台退出 experimental gating，且 host/runtime boundary 完成加固。</li></ul><h2 id="成功标准" tabindex="-1">成功标准 <a class="header-anchor" href="#成功标准" aria-label="Permalink to &quot;成功标准&quot;">​</a></h2><ul><li>路线图与需求文档能够如实反映当前代码，不再出现明显失真宣称。</li><li>维护者无需重新通读整个 diagram 代码库，仅凭文档就能决定下一批实现工作。</li><li>下一批工作被明确表述为“稳定化、命令架构、runtime 边界”，而不是功能蔓延。</li><li>在 phase-2 planning 或直接执行前，不再存在阻塞性的产品问题。</li></ul><h2 id="范围边界" tabindex="-1">范围边界 <a class="header-anchor" href="#范围边界" aria-label="Permalink to &quot;范围边界&quot;">​</a></h2><ul><li>本次 brainstorm 不新增 renderer 实现。</li><li>本次 brainstorm 不退役 legacy Mermaid fixer 路径。</li><li>本次 brainstorm 不宣称 iframe-host 已经把重型 runtime 从主插件 bundle 中隔离出来。</li><li>本次 brainstorm 本身不创建新的 release 或 tag。</li></ul><h2 id="关键决策" tabindex="-1">关键决策 <a class="header-anchor" href="#关键决策" aria-label="Permalink to &quot;关键决策&quot;">​</a></h2><ul><li>更新现有 roadmap，而不是重写一份新的。它已经是实现锚点，应被提升为权威状态文档。</li><li>新增一份专门的 phase-2 requirements 文档。roadmap 描述执行切片，这份文档定义下一阶段必须优化什么。</li><li>将 diagram platform 视为“核心能力已落地，但尚未完全产品化”。核心模块已经存在，但 experimental gating、runtime isolation 与 legacy 路径收缩仍未完成。</li><li>优先做边界加固，而不是新增 renderer 扩展。当前最高杠杆动作是稳定现有平台，而不是继续拉长 target 列表。</li></ul><h2 id="依赖与假设" tabindex="-1">依赖与假设 <a class="header-anchor" href="#依赖与假设" aria-label="Permalink to &quot;依赖与假设&quot;">​</a></h2><ul><li><code>README.md</code> 与 <code>docs/releases/1.8.2.md</code> 已经记录当前实验性图表功能集，并应继续与代码保持一致。</li><li><code>ref/**</code> 仅作为本地参考材料，不属于发货范围。</li><li>发布质量级改动仍沿用 <code>npm run build</code>、<code>npm test -- --runInBand</code>、<code>npm run audit:i18n-ui</code>、<code>npm run audit:render-host</code> 与 <code>git diff --check</code> 作为完整仓库验证门禁。</li></ul><h2 id="未决问题" tabindex="-1">未决问题 <a class="header-anchor" href="#未决问题" aria-label="Permalink to &quot;未决问题&quot;">​</a></h2><h3 id="延后到规划阶段" tabindex="-1">延后到规划阶段 <a class="header-anchor" href="#延后到规划阶段" aria-label="Permalink to &quot;延后到规划阶段&quot;">​</a></h3><ul><li>[影响 R4][Technical] best-fit diagram generation 需要满足哪些明确验收门槛，才能从 developer-only / experimental 状态升级为 stable opt-in 或 default-on？</li><li>[影响 R8][Technical] 剩余 diagram orchestration 路径中，哪些应优先从 <code>src/main.ts</code> 迁出，避免平台继续沿着插件入口膨胀？</li><li>[影响 R9][Needs research] 一旦 release asset packaging 形式被正式化，更重的 preview runtime 应放在内联 <code>srcdoc</code>、独立 bundle frame，还是 hybrid loader？</li></ul><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><p>-&gt; 直接推进 phase-2 稳定化批次，或先使用 <code>/ce:plan</code> 形成更正式的执行拆解。</p>',27)])])}const u=a(t,[["render",o]]);export{p as __pageData,u as default};
